/* ============================================================
   CSS Reset — browser normalization only.
   Loaded into the `base` cascade layer by $CoreThemeManager.
   ============================================================ */
html {
  box-sizing: border-box;
  font-size: 16px;
}

*,
*:before,
*:after {
  box-sizing: inherit;
}

html,
body {
  height: 100%;
  margin: 0;
}

body,
p,
ol,
ul {
  margin: 0;
  padding: 0;
  font-weight: normal;
}

ol,
ul {
  list-style: none;
}

img {
  max-width: 100%;
  height: auto;
}

a {
  text-decoration: none;
}

a:hover {
  text-decoration: underline;
}

a[data-msg]:hover {
  cursor: pointer;
}

/* ============================================================
   Design tokens — the single source of truth for every CSS
   variable used anywhere in core or themes, with light defaults.
   Loaded into the `base` cascade layer by $CoreThemeManager.
   Themes override individual tokens from the `theme` layer.
   ============================================================ */
:root {
  /* ---- Backgrounds ---- */
  --colbg1: #fdeeee; /* main pane behind notes */
  --colbg2: #efefef; /* note cards, dialogs, popovers */
  --colbg3: #dfdfdf; /* sidebar, tab strip, raised chrome */
  --colbgi: #efefef; /* form inputs */

  /* ---- Foreground ---- */
  --colfg:  #323232; /* body text */
  --colfgi: #373737; /* input text */

  /* ---- Neutrals & accents ---- */
  --col0: #323232;   /* shadows */
  --col1: #6e6e6e;   /* muted text, icons */
  --col3: #8fbfdf;   /* filled controls (buttons, th) */
  --col4: #8d8d8d;   /* hairline borders */
  --col6: #6db193;   /* links, hover accent */

  /* ---- Foreground over accent/error/notify backgrounds ---- */
  --col-on-accent: #fff;

  /* ---- Error / critical / warning ---- */
  --col-error: #c0392b;
  --col-warning: #e0a000;

  /* ---- Notification background (rgba components) ---- */
  --notify-rgba: 210, 180, 90;

  /* ---- Radii ---- */
  --rad1: 0.3rem;
  --rad2: 0.3rem;
  --rad3: 0.3rem;
  --rad4: 0.3rem;

  /* ---- Layout tokens ---- */
  --sidebar-w: 280px;
  --accent: #6db193;
  --accent-2: #8fbfdf;

  /* ---- Search ---- */
  --search-hit-bg: #fff59d; /* highlighted search hit (SearchHighlightPlugin) */

  /* Derive tab colours from the palette so every theme gets sensible
     tabs without redefining them: inactive matches the top-bar/chrome
     (--colbg3); active matches the note pane (--colbg2). A theme can
     still override these explicitly. */
  --tab-bg: var(--colbg3);
  --tab-active-bg: var(--colbg2);
}

/* ============================================================
   Universal component appearance for the 3-pane UI.
   Token-driven: themes recolour everything by overriding the
   CSS variables (defaults live in $BaseVariables).
   Structure/layout lives in $CoreThemeLayout; this file is looks.
   Part of the active theme's bullet list (loaded into `theme` layer).
   ============================================================ */

* {
  font-family:
    -apple-system,
    system-ui,
    'Segoe UI',
    Inter,
    Roboto,
    Helvetica,
    Arial,
    sans-serif;
}

body {
  background-color: var(--colbg1);
  color: var(--colfg);
  font-size: 0.95rem;
  line-height: 1.5;
}

a:not([class]) {
  color: var(--col6);
  font-weight: 600;
  text-decoration-skip-ink: auto;
}

/* Thin, unobtrusive scrollbars everywhere */
* {
  scrollbar-width: thin;
  scrollbar-color: var(--col4) transparent;
}

/* ============================================================
   Sidebar + explorer
   ============================================================ */
#sidebar {
  border-right: 1px solid var(--col4);
}

#sidebar > #header {
  padding: 12px 14px 6px;
}

#site-title h1 {
  font-size: 1.15rem;
  font-weight: 700;
  padding: 0;
  margin: 0;
  letter-spacing: -0.01em;
}

#site-subtitle {
  font-size: 0.75rem;
  color: var(--col1);
}

#explorer-search {
  padding: 6px 12px 10px;
}

#explorer {
  padding: 4px 8px 12px;
}

/* Sidebar footer: existing toolbar + selectors */
#sidebar-footer {
  border-top: 1px solid var(--col4);
  padding: 8px 12px;
}

#header-tools {
  display: flex;
  flex-wrap: wrap;
  gap: 4px;
  align-items: center;
}

.sidebar-selectors {
  display: flex;
  gap: 6px;
  margin-top: 8px;
}

/* ============================================================
   Main pane — top bar, tabs
   ============================================================ */
#main-topbar {
  background-color: var(--colbg3);
  border-bottom: 1px solid var(--col4);
  min-height: 38px;
}

#menu-toggle {
  padding: 0 12px;
  font-size: 1.1rem;
  color: var(--col1);
  background: transparent;
  border: none;
}

/* ============================================================
   Notes (cards / active pane)
   ============================================================ */
#visible-tiddlers {
  padding: 0;
}

div.tiddler {
  max-width: 860px;
  margin: 24px auto;
  padding: 24px 32px;
  background-color: var(--colbg2);
  border: 1px solid var(--col4);
  border-radius: var(--rad1) var(--rad2) var(--rad3) var(--rad4);
}

div.tiddler-nosave {
  border-color: var(--col6);
}

div.tiddler-readonly {
  border-left: 3px solid var(--col1);
}

div.shadowtrue {
  border-left: 3px solid var(--col4);
}

div.shadowtrue div.title {
  font-style: italic;
}

div.tiddler div.title {
  font-size: 1.6rem;
  font-weight: 700;
  line-height: 1.25;
  letter-spacing: -0.01em;
  padding-bottom: 10px;
  margin-bottom: 14px;
  border-bottom: 1px solid var(--col4);
}

div.tiddler div.title button {
  border: none;
  background: transparent;
  float: right;
}

div.tiddler div.modified {
  text-align: right;
  font-style: italic;
  font-size: 0.78rem;
  color: var(--col1);
}

div.tiddler div.text {
  scrollbar-color: var(--col4) transparent;
  scrollbar-width: thin;
}

div.tiddler div.text p {
  margin: 14px 0;
}

div.tiddler div.tags {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
  align-items: center;
  font-size: 0.78rem;
  color: var(--col1);
  margin-top: 16px;
}

/* Tag pills are picker triggers (see PickerPlugin); style them like the
   explorer's tag pills rather than the generic icon trigger. */
.picker-trigger.tag-pill {
  padding: 2px 10px;
  border-radius: 999px;
  background-color: var(--colbg2);
  border: 1px solid var(--col4);
  color: var(--col1);
  font-size: 0.78rem;
  line-height: 1.4;
  cursor: pointer;
}

.picker-trigger.tag-pill:hover {
  color: var(--col6);
  border-color: var(--col6);
  background-color: var(--colbg2);
}

/* The package pill (footer .meta) is a picker trigger too — a quieter pill that
   fits the small meta line; clicking it lists the package's tiddlers. */
.picker-trigger.pck-pill {
  padding: 1px 8px;
  border-radius: 999px;
  background-color: var(--colbg2);
  border: 1px solid var(--col4);
  color: var(--col1);
  font-size: 0.72rem;
  line-height: 1.4;
  cursor: pointer;
}

.picker-trigger.pck-pill:hover {
  color: var(--col6);
  border-color: var(--col6);
}

div.tiddler div.meta {
  text-align: right;
  font-size: 0.72rem;
  color: var(--col1);
}

/* ============================================================
   Buttons
   ============================================================ */
button {
  fill: var(--col1);
  color: var(--colfg);
  border: 1px solid var(--col4);
  background-color: var(--col3);
  border-radius: var(--rad1);
  padding: 4px 10px;
  cursor: pointer;
}

button:hover {
  filter: brightness(1.1);
}

button.icon {
  fill: var(--col1);
  background-color: transparent;
  border: none;
  padding: 4px;
  cursor: pointer;
}

button.icon:hover svg,
button:hover svg {
  fill: var(--col6);
}

/* ============================================================
   Forms & inputs
   ============================================================ */
input,
textarea,
select {
  background-color: var(--colbgi);
  color: var(--colfgi);
  border: 1px solid var(--col4);
  border-radius: var(--rad1);
  padding: 6px 8px;
  font-size: 0.9rem;
}

input:focus,
textarea:focus,
select:focus {
  outline: none;
  border-color: var(--col6);
}

#search {
  padding: 8px 10px;
}

#search-results {
  padding: 8px;
  background: var(--colbg2);
  border: 1px solid var(--col4);
  border-radius: var(--rad1);
  box-shadow: 0 6px 24px rgba(0, 0, 0, 0.4);
}

#search-results .tiddler-list {
  padding: 4px 8px;
  border-radius: var(--rad1);
}

#search-results .tiddler-list:hover {
  background-color: var(--colbg3);
}

#search-results .tiddler-list[data-msg] {
  cursor: pointer;
}

#search-results a {
  color: var(--colfg);
}

/* ============================================================
   Dialogs (edit / preview)
   ============================================================ */
dialog::backdrop {
  background-color: rgba(0, 0, 0, 0.6);
  backdrop-filter: blur(2px);
}

/* Core dialog (tw.ui.dialog) — shared chrome for all plugin dialogs */
dialog.tw-dialog {
  background-color: var(--colbg2);
  color: var(--colfg);
  border: 1px solid var(--col4);
  border-radius: var(--rad1);
  padding: 1rem;
  min-width: min(420px, 92vw);
  max-width: min(720px, 92vw);
  max-height: 80vh;
  overflow: auto;
}

dialog.tw-dialog .tw-dialog-title {
  margin: 0 0 0.6rem;
}

dialog.tw-dialog .tw-dialog-toolbar {
  text-align: right;
  margin-top: 0.75rem;
}

dialog.tw-dialog .tw-dialog-toolbar button {
  margin-left: 0.4rem;
}

dialog#new-dialog {
  width: 70%;
  height: 75%;
  background-color: var(--colbg2);
  color: var(--colfg);
  border: 1px solid var(--col4);
  border-radius: var(--rad1);
}

dialog#new-dialog form {
  width: 100%;
  height: 100%;
  display: flex;
  flex-direction: column;
  gap: 8px;
}

dialog#new-dialog form div.text {
  flex-grow: 1;
  min-height: 240px;
}

dialog#new-dialog form input,
dialog#new-dialog form textarea {
  width: 100%;
  height: 100%;
}

/* Tiddler-body editor: monospace for legible code/markup editing across all themes.
   `ui-monospace` picks the OS default (SF Mono on macOS, Cascadia Mono on Win11). */
dialog#new-dialog form textarea {
  font-family: ui-monospace, SFMono-Regular, Menlo, Consolas, 'Liberation Mono', monospace;
  font-size: 0.9rem;
  line-height: 1.5;
  tab-size: 2;
}

dialog#new-dialog div.title input {
  font-size: 1.2rem;
  font-weight: 700;
}

dialog#new-dialog div.toolbar {
  text-align: right;
}

dialog#preview-dialog {
  width: 90%;
  height: 90%;
  min-height: 500px;
  border: 0;
  background-color: transparent;
  overflow-y: hidden;
}

dialog#preview-dialog div.tiddler {
  height: 100%;
  max-width: none;
  margin: 0;
}

dialog#preview-dialog div.text {
  height: 100%;
  max-height: 1000px;
}

/* ============================================================
   Notifications
   ============================================================ */
#notify {
  position: fixed;
  z-index: 30;
  left: 50%;
  transform: translate(-50%);
  bottom: 16px;
  min-width: 250px;
  max-width: 80vw;
  background-color: rgba(var(--notify-rgba), 0.96);
  color: var(--col-on-accent);
  text-align: left;
  border-radius: var(--rad1);
  box-shadow: 0 8px 28px rgba(0, 0, 0, 0.5);
  padding: 14px 18px;
  line-height: 1.35;
}

div.notifyHidden {
  visibility: hidden;
  opacity: 0;
  transition: visibility 0.3s linear, opacity 0.3s linear;
}

div.notifyShow {
  visibility: visible;
  opacity: 1;
  transition: visibility 0.3s linear, opacity 0.3s linear;
}

/* ============================================================
   Typography & content
   ============================================================ */
h1 { font-size: 1.8rem; padding: 4px 0; }
h2 { font-size: 1.45rem; padding: 4px 0; }
h3 { font-size: 1.2rem; padding: 3px 0; }
h4 { font-size: 1.05rem; padding: 2px 0; }

div.tiddler ul,
div.tiddler ol {
  margin-left: 1.4em;
  margin-bottom: 0.6em;
}

div.tiddler ul { list-style: disc; }
div.tiddler ol { list-style: decimal; }

li li {
  margin-left: 16px;
}

blockquote {
  background-color: var(--colbg3);
  border-left: 4px solid var(--col6);
  margin: 1.2em 0;
  padding: 0.6em 1em;
  border-radius: 0 var(--rad1) var(--rad1) 0;
  quotes: "\201C" "\201D" "\2018" "\2019";
}

code {
  background-color: var(--colbg3);
  font-family: 'Cascadia Code', Consolas, 'Courier New', monospace;
  padding: 0.15rem 0.4rem;
  margin: 0 0.15rem;
  font-size: 88%;
  border: 1px solid var(--col4);
  border-radius: 4px;
}

pre {
  white-space: pre-wrap;
}

pre > code {
  display: block;
  padding: 1rem 1.25rem;
  white-space: pre;
  overflow-x: auto;
}

table {
  border-collapse: collapse;
}

th,
td {
  padding: 6px 10px;
  border: 1px solid var(--col4);
}

th {
  font-weight: 700;
  background-color: var(--col3);
  color: var(--col-on-accent);
}

span.error {
  color: var(--col-on-accent);
  background-color: var(--col-error);
  padding: 0 4px;
  border-radius: 3px;
}

/* ============================================================
   Dark palette — token overrides for $CoreThemeDark.
   Pure :root overrides; structure and component appearance are
   inherited from $CoreThemeLayout / $CoreThemeAppearance.
   Part of the active theme's bullet list (loaded into `theme` layer).
   ============================================================ */
:root {
  --colbg1: #101f1f;
  --colbg2: #101f1f;
  --colbg3: #2a2a2a;
  --colbgi: #3f3f3f;
  --colfgi: #d7d7d7;
  --colfg: rgb(205, 205, 205);
  --col0: #cdcdcd;
  --col1: #6e6e6e;
  --col3: #8fbfdf;
  --col4: #8d8d8d;
  --col6: #6db193;
}

/* ============================================================
   App shell — 3-pane grid (sidebar | main)
   Structural only; colours/typography come from $CoreThemeAppearance.
   Part of the active theme's bullet list (loaded into `theme` layer).
   ============================================================ */
#app {
  display: grid;
  grid-template-columns: var(--sidebar-w, 280px) 1fr;
  width: 100%;
  height: 100vh;
  overflow: hidden;
}

/* ---- Left sidebar ---- */
#sidebar {
  display: flex;
  flex-direction: column;
  min-height: 0;
  overflow: hidden;
  background-color: var(--colbg3);
}

#sidebar > #header {
  flex: 0 0 auto;
}

#explorer-search {
  flex: 0 0 auto;
  position: relative;
}

#explorer-search #search {
  width: 100%;
}

#search-results {
  position: absolute;
  left: 0;
  right: 0;
  top: 100%;
  z-index: 5;
  max-height: 60vh;
  overflow-y: auto;
  background: var(--colbg2);
}

#explorer {
  flex: 1 1 auto;
  min-height: 0;
  overflow-y: auto;
}

#sidebar-footer {
  flex: 0 0 auto;
}

/* ---- Main pane ---- */
#main {
  display: flex;
  flex-direction: column;
  min-width: 0;
  min-height: 0;
  overflow: hidden;
}

#main-topbar {
  flex: 0 0 auto;
  display: flex;
  align-items: stretch;
}

#tab-strip {
  flex: 1 1 auto;
  display: flex;
  align-items: stretch;
  overflow-x: hidden;
  overflow-y: hidden;
}

#visible-tiddlers {
  flex: 1 1 auto;
  min-height: 0;
  overflow-y: auto;
}

#menu-toggle {
  display: none;
  flex: 0 0 auto;
}

/* Tabbed story: show only the active note. Gated behind `.tabbed`
   (added by the tabs plugin) so this is a no-op when the plugin is
   absent — notes then simply stack as before. */
#visible-tiddlers.tabbed > .tiddler {
  display: none;
}

#visible-tiddlers.tabbed > .tiddler.tab-active {
  display: block;
}

/* River mode: no tabs — every open note stacks (the .tabbed rule above is off).
   Hide the strip and collapse the now-empty top bar (the mobile menu-toggle
   still keeps it visible on small screens). */
.mode-river #tab-strip {
  display: none;
}

.mode-river #main-topbar {
  min-height: 0;
  border-bottom: none;
}

/* ============================================================
   Header-bar layout ($MainLayoutHeader) — structural only.
   A top header bar over the main content (no left explorer pane;
   navigation is via search + tabs). Scoped to #app.layout-header
   so the default sidebar grid is untouched; visuals come from the theme.
   ============================================================ */
#app.layout-header {
  display: flex;
  flex-direction: column;
}

#app.layout-header > #header {
  flex: 0 0 auto;
  display: flex;
  align-items: center;
  gap: 0.5rem;
}

#app.layout-header #header-col1 {
  flex: 0 0 auto;
}

#app.layout-header #header-col2 {
  flex: 0 0 auto;
  display: flex;
  align-items: center;
  gap: 0.25rem;
}

#app.layout-header #header-col3 {
  flex: 1 1 auto;
  position: relative;
}

#app.layout-header #header-col3 #search {
  width: 100%;
}

#app.layout-header > #main {
  flex: 1 1 auto;
  min-height: 0;
}

/* ============================================================
   Responsive — sidebar collapses to a slide-in drawer
   ============================================================ */
@media (max-width: 600px) {
  html {
    font-size: 14px;
  }

  #app {
    grid-template-columns: 1fr;
  }

  #sidebar {
    position: fixed;
    z-index: 20;
    top: 0;
    bottom: 0;
    left: 0;
    width: min(85vw, var(--sidebar-w, 280px));
    transform: translateX(-100%);
    transition: transform 0.2s ease;
    box-shadow: 2px 0 12px var(--col0);
  }

  #sidebar.open {
    transform: translateX(0);
  }

  #menu-toggle {
    display: inline-flex;
    align-items: center;
  }
}

